text:
Updated patch fixing more missing references.  This allows
net-p2p/rtorrent-devel to link with the produced library.

Index: Makefile
===================================================================
--- Makefile	(revision 336929)
+++ Makefile	(working copy)
@@ -38,9 +38,9 @@

 CONFIGURE_ARGS+=	--disable-debug

-# Workaround to build on > 10.x
 .if ${OSVERSION} >= 1000000
-USE_GCC=	yes
+CXXFLAGS+=-std=c++11
+EXTRA_PATCHES+=${PATCHDIR}/extra-patch-fix-clang-build.diff
 .endif

